cd $SANDBOX && cat > zz_gt_test.go <<'EOF'
package ratelimit
import "testing"
func TestGTLimiter(t *testing.T) {
	l := NewLimiter()
	for i := 0; i < 3; i++ { if !l.Take("a") { t.Fatalf("a take %d", i) } }
	if l.Take("a") { t.Fatalf("a should be throttled") }
	// separate key must be unaffected
	if !l.Take("b") { t.Fatalf("b should start fresh") }
	// refill restores a
	l.Replenish(1)
	if !l.Take("a") { t.Fatalf("a should be allowed after replenish") }
	if l.Take("a") { t.Fatalf("a should be throttled again") }
}
EOF
go test ./... && rm -f zz_gt_test.go
